  render: () => <Container padded rounded style={{
    backgroundColor: 'white'
  }}>
      <Stack gap="15px">
        <Stack gap={7}>
          <Heading level={2}>Custom Field Integrations</Heading>
          <Text>Manage and configure your custom fields with ease.</Text>
        </Stack>
        <Container bordered padded rounded>
          <Stack direction="horizontal" gap={'var(--pac-upui-space-large)'} alignItems="flex-start">
            <img style={{
            width: 74,
            borderRadius: 4
          }} alt="logo" src={'https://ps.w.org/advanced-custom-fields/assets/icon.svg?rev=3207824'} />
            <Stack>
              <Stack direction="horizontal" alignItems="center">
                <Heading level={3}>Advanced Custom Fields (ACF)</Heading>
                <Badge variant="active" badgeText="Active" />
              </Stack>
              <Text>
                This section highlights that ACF fields are fully supported by Divi Dynamic Content
                Helper. You can edit ACF field values directly in the Divi Builder's Custom Fields
                panel and leverage them with features like inline variables and global dynamic
                content sources. This ensures seamless integration for sites using ACF, giving you
                full control over dynamic content without leaving the builder.
              </Text>
            </Stack>
          </Stack>
        </Container>
        <Container bordered padded rounded>
          <Stack direction="horizontal" gap={'var(--pac-upui-space-large)'} alignItems="flex-start">
            <img style={{
            width: 74,
            borderRadius: 4
          }} alt="logo" src={'https://ps.w.org/advanced-custom-fields/assets/icon.svg?rev=3207824'} />
            <Stack>
              <Stack direction="horizontal" alignItems="center">
                <Heading level={3}>Advanced Custom Fields (ACF)</Heading>
                <Badge variant="notinstalled" />
              </Stack>
              <Text>
                This section highlights that ACF fields are fully supported by Divi Dynamic Content
                Helper. You can edit ACF field values directly in the Divi Builder's Custom Fields
                panel and leverage them with features like inline variables and global dynamic
                content sources. This ensures seamless integration for sites using ACF, giving you
                full control over dynamic content without leaving the builder.
              </Text>
            </Stack>
          </Stack>
        </Container>
      </Stack>
    </Container>
